#include<bits/stdc++.h>
#define int long long
using namespace std;
const int N = 1e3 + 7,inf = -1e18;
int T, n, m;
int dp[10007],a[N][N];
signed main(){
	cin >> T >> n >> m;		
	for(int i = 1; i <= T; i++){
		for(int j = 1; j <= n; j++){
			cin >> a[i][j];
		}
	}
	int k = 1;
	while(k <= T){
		memset(dp,inf,sizeof(dp));
	//	cout << m << endl;
		dp[m] = m;
		for(int i = 1; i <= n; i++){
			for(int j = m; j >= a[k][i]; j--){
				dp[j - a[k][i]] = max(dp[j - a[k][i]], dp[j] + a[k + 1][i] - a[k][i]);
			}
		}
		int maxi = inf;
		for(int i = 0; i <= m; i++) maxi = max(maxi,dp[i]);
//		cout << maxi << endl;

		m = maxi;
		k++;
	} 
	cout << m;
	return 0; 
}
